export interface DataPoint {
  date: string;
  value: number;
}

export interface EconomicIndicator {
  id: string;
  name: string;
  unit: string;
  frequency: 'Monthly' | 'Quarterly';
  sourceName: string;
  sourceUrl: string;
  data: DataPoint[];
  description: string;
}

export interface DashboardState {
  indicators: EconomicIndicator[];
  loading: boolean;
  error: string | null;
  lastUpdated: string | null;
  groundingSources: Array<{ title: string; uri: string }>;
}

import { GoogleGenAI } from "@google/genai";
import { INDICATOR_CONFIGS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchEconomicData = async () => {
  const prompt = `
    Find the latest 12 months (or last 4-6 available quarters) of data for the following economic indicators in the Philippines and global oil market:
    1. WTI Crude Oil Spot Price (Monthly)
    2. Philippines CPI (Consumer Price Index) (Monthly)
    3. Philippines Inflation Rate (Monthly)
    4. Philippines GDP (Constant Prices) Growth Rate (Quarterly)
    5. Philippines Unemployment Rate (Quarterly)
    6. Philippines GNI and GDP (focusing on Wholesale and Retail Trade) (Quarterly)

    Return the data strictly as a valid JSON object with the following structure:
    {
      "indicators": [
        {
          "id": "wti-oil",
          "data": [{"date": "2024-01", "value": 75.5}, ...]
        },
        ... (repeat for all 6 IDs: wti-oil, cpi-ph, inflation-ph, gdp-growth, unemployment, gni-gdp-ratio)
      ]
    }

    Ensure the "date" field uses "YYYY-MM" format for monthly and "YYYY-QN" (e.g., 2024-Q1) for quarterly.
    Use only the most recent available real-world data.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";
    // Extract JSON from the markdown-wrapped response
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      throw new Error("Failed to parse indicator data from Gemini response.");
    }

    const rawData = JSON.parse(jsonMatch[0]);
    const groundingSources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map(chunk => ({
      title: chunk.web?.title || "Search Result",
      uri: chunk.web?.uri || "#"
    })) || [];

    // Map fetched data to our config structure
    const indicators = INDICATOR_CONFIGS.map(config => {
      const fetched = rawData.indicators.find((ind: any) => ind.id === config.id);
      return {
        ...config,
        data: fetched ? fetched.data : []
      };
    });

    return {
      indicators,
      groundingSources
    };
  } catch (error) {
    console.error("Error fetching data from Gemini:", error);
    throw error;
  }
};

import { EconomicIndicator } from '../types';

export const exportToCSV = (indicator: EconomicIndicator) => {
  const headers = ['Date', `Value (${indicator.unit})`];
  const rows = indicator.data.map(dp => [dp.date, dp.value.toString()]);

  const csvContent = [
    headers.join(','),
    ...rows.map(row => row.join(','))
  ].join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `${indicator.id}_data_${new Date().toISOString().split('T')[0]}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

